@startuml
participant "A" as DaoSupport
participant "I" as PersonService
participant "C" as PersonServiceBean

DaoSupport <<Database>>
DaoSupport {
    void save(Object e)
    void delete(Integer id)
}

PersonService <<Interface>>
PersonService {
    void delete(Integer id)
}

PersonServiceBean <<Service>>
PersonServiceBean {
    void delete(Integer id)
}

DaoSupport..> PersonServiceBean : 泛化即继承关系

PersonService..> PersonServiceBean : 实现关系

@enduml
